/**
 * @file CountryCodePickerV8.tsx
 * @module v8/components
 * @description Country code picker with flags for phone number input
 * @version 8.0.0
 * @since 2024-11-19
 *
 * @example
 * <CountryCodePickerV8
 *   value="+1"
 *   onChange={(code) => setCountryCode(code)}
 * />
 */

